%%%%%%%%%% Function fBinArryV01.m %%%%%%%%%%% bin array, ver.1%% Kei Nakamura% Created on Friday, April 24th 2009.% Modified on %% function out = fBinArryV01(in,dgr);% return binned array% out: output array% in: input array% dgr: degree of binningfunction out = fBinArryV01(in,dgr)inSiz = max(size(in));   % size of input arrayoutSiz = floor(inSiz/dgr);  % size of output arrayoutM = zeros(dgr,outSiz);for i=1:dgr    outM(i,:) = in(i:dgr:(outSiz-1)*dgr+i);endout = sum(outM);
